import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: never,
  policyName: string
) {
  const origin = request.headers.get("origin");
  const runId = process.env.ZEALT_RUN_ID;
  const allowedOrigin = `https://example-${runId}.com`;

  const isAllowed = origin === allowedOrigin;

  if (request.method === "OPTIONS") {
    if (isAllowed) {
      return new Response(null, {
        status: 204,
        headers: {
          "Access-Control-Allow-Origin": allowedOrigin,
          "Access-Control-Allow-Methods": "GET, OPTIONS",
          "Access-Control-Allow-Headers": "Content-Type, Authorization",
        },
      });
    } else {
      return new Response(null, { status: 204 });
    }
  }

  if (typeof context.addResponseSendingHook === "function") {
    context.addResponseSendingHook((response: Response) => {
      if (isAllowed) {
        // Response headers are read-only if it's a native Response, we need to create a new one or modify if possible
        const newHeaders = new Headers(response.headers);
        newHeaders.set("Access-Control-Allow-Origin", allowedOrigin);
        return new Response(response.body, {
          status: response.status,
          statusText: response.statusText,
          headers: newHeaders,
        });
      }
      return response;
    });
  }

  return request;
}
